function ShareWith(message, Title) {
    if ("Facebook" == Title) {
        var url = "https://www.facebook.com/dialog/share?" + message;
        window.open(url, "shareWindowFacebook", "top=100,left=500,width=450,height=300")
    } else if ("Twitter" == Title) {
        url = "https://twitter.com/intent/tweet?&text=" + message;
        window.open(url, "shareWindowTwitter", "top=100,left=500,width=450,height=300")
    } else
        "Print" == Title && window.print()
}
function updateQueryStringParameter(uri, key, value) {
    var re = new RegExp("([?&])" + key + "=.*?(&|$)","i")
      , separator = -1 !== uri.indexOf("?") ? "&" : "?";
    return uri.match(re) ? uri.replace(re, "$1" + key + "=" + value + "$2") : uri + separator + key + "=" + value
}
function urlParam(name) {
    var results = new RegExp("[?&]" + name + "=([^]*)").exec(window.location.href);
    return null == results ? null : results[1] || 0
}
